                'workflow_step': 'approval_pending',
                'order_id': '123'
            }
        }
    )

    # Extract workflow state for verification
    final_state = None
    for event in response.get('completion', []):
        if 'trace' in event:
            trace = json.loads(event['trace']['bytes'])
            if 'sessionState' in trace:
                final_state = trace['sessionState']
    return final_state

