import { verify } from 'vex-sdk';

const idempotencyCheck = async (agentResponse: any, txContext: any) => {
  const result = await verify({
    idempotency: {
      requestId: agentResponse.trace.requestId,
      existingTx: txContext.currentTransaction,
      operation: agentResponse.actionGroup
    },
    rollback_capability: {
      compensations: txContext.compensationActions,
      critical: agentResponse.isCritical
    },
    workflow_state: {
      expected_step: txContext.nextStep,
      actual_step: agentResponse.nextStep
    }
  });

  if (!result.valid) {
    // Execute rollback
    await executeRollback(txContext.compensations);
    throw new Error(`Verification failed: ${JSON.stringify(result.errors)}`);
  }

  return result;
};

const executeRollback = async (compensations: any[]) => {
  for (const compensation of compensations) {
    await compensation.execute();
  }
};
